fn solve(s: String) -> String {
    let mut result = String::new();
    for c in s.chars() {
        if c.is_ascii_lowercase() {
            result.push(c);
        } else if c == '*' {
            if !result.is_empty() {
                result.pop();
            }
        } else if c == '#' {
            result.push_str(&result);
        } else if c == '%' {
            let mut chars: Vec<char> = result.chars().collect();
            chars.reverse();
            result = chars.into_iter().collect();
        }
    }
    result
}
```

